async (params, browser) => {
  // Open Duolingo learn page (leaderboard is in sidebar)
  await browser.open('https://www.duolingo.com/learn')

  // Wait for page
  await browser.waitForSelector('[class*="leaderboard"], [class*="Leaderboard"], .content', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const entries = []; document.querySelectorAll('[class*="leaderboard"] li, [class*="Leaderboard"] tr, [class*="row"]').forEach((el, i) => { if (i < 20) { const nameEl = el.querySelector('[class*="name"], a, span'); const xpEl = el.querySelector('[class*="xp"], [class*="score"]'); entries.push({ rank: i + 1, name: nameEl?.textContent?.trim() || '', xp: xpEl?.textContent?.trim() || '' }); } }); return { entry_count: entries.length, entries };`)

  return result
}
